import akka.actor.{Actor, ActorLogging, Props}
import scala.math.BigDecimal

// Define messages for the actor
object AccountActor {
  case class Deposit(amount: BigDecimal)
  case class Withdraw(amount: BigDecimal)
  case object GetBalance

  // Responses
  case class BalanceResponse(balance: BigDecimal)
  case class TransactionResult(success: Boolean, newBalance: Option[BigDecimal] = None, message: Option[String] = None)

  def props: Props = Props(new AccountActor)
}

// Actor implementation
class AccountActor extends Actor with ActorLogging {
  import AccountActor._

  // Mutable balance variable, safely managed by the actor's sequential message processing.
  var balance: BigDecimal = BigDecimal(0)

  def receive: Receive = {
    case Deposit(amount) =>
      if (amount <= BigDecimal(0)) {
        sender() ! TransactionResult(false, message = Some("Deposit amount must be positive"))
      } else {
        balance += amount
        log.info(s"Deposited $amount. New balance: $balance")
        sender() ! TransactionResult(true, Some(balance))
      }

    case Withdraw(amount) =>
      if (amount <= BigDecimal(0)) {
        sender() ! TransactionResult(false, message = Some("Withdrawal amount must be positive"))
      } else if (balance >= amount) {
        balance -= amount
        log.info(s"Withdrew $amount. New balance: $balance")
        sender() ! TransactionResult(true, Some(balance))
      } else {
        log.warning(s"Attempted to withdraw $amount but balance is $balance. Insufficient funds.")
        sender() ! TransactionResult(false, message = Some("Insufficient funds"))
      }

    case GetBalance =>
      sender() ! BalanceResponse(balance)
  }
}